// UART Transmitter - 9600 baud
module top_module (
    input clk,
    input reset,
    input [7:0] data,
    output reg [7:0] q
);

    always @(posedge clk) begin
        if (reset) begin
            q <= 8'b00000000;
        end else begin
            q <= data;
        end
    end

endmodule
